### 6. SAMPLE GRPC PROTO FILE CONVENTIONS

From the documented examples, here's the pattern:

```protobuf
syntax = "proto3";
package feature;

option java_multiple_files = true;
option java_package = "com.maum.backend.protobuf.feature";

service FeatureService {
  rpc GetFeature(GetFeatureRequest) returns (GetFeatureResponse);
  rpc CreateFeature(CreateFeatureRequest) returns (CreateFeatureResponse);
  rpc ListFeatures(ListFeaturesRequest) returns (ListFeaturesResponse);
  rpc DeleteFeature(DeleteFeatureRequest) returns (DeleteFeatureResponse);
}

message GetFeatureRequest {
  string user_id = 1;
  string feature_id = 2;
}

message GetFeatureResponse {
  Feature feature = 1;
}

message CreateFeatureRequest {
  string user_id = 1;
  string name = 2;
}

message CreateFeatureResponse {
  Feature feature = 1;
}

message ListFeaturesRequest {
  string user_id = 1;
  int32 limit = 2;
  int32 offset = 3;
}

message ListFeaturesResponse {
  repeated Feature features = 1;
  int32 total = 2;
}

message DeleteFeatureRequest {
  string feature_id = 1;
}

message DeleteFeatureResponse {
  bool success = 1;
}

message Feature {
  string id = 1;
  string name = 2;
  string user_id = 3;
  string created_at = 4;
  string updated_at = 5;
}
```

### 7. EXISTING GRPC SERVICE IMPLEMENTATIONS

**gRPC Client Stub Usage** (in GraphQL module):

```kotlin
@Service
class FeatureService {
    @GrpcClient("feature-grpc")
    private lateinit var featureStub: FeatureServiceGrpc.FeatureServiceBlockingStub

    fun getFeature(userId: String, featureId: String): GetFeatureResponse {
        val request = GetFeatureRequest.newBuilder()
            .setUserId(userId)
            .setFeatureId(featureId)
            .build()
        return try {
            featureStub.getFeature(request)
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException(e.trailers!!, e.status.description)
        }
    }

    fun listFeatures(userId: String, limit: Int, offset: Int): ListFeaturesResponse {
        val request = ListFeaturesRequest.newBuilder()
            .setUserId(userId)
            .setLimit(limit)
            .setOffset(offset)
            .build()
        return try {
            featureStub.listFeatures(request)
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException(e.trailers!!, e.status.description)
        }
    }
}
```

**gRPC Server Implementation** (in Microservice module):

```kotlin
@GrpcService
class FeatureGrpcService(
    private val featureService: FeatureService,
) : FeatureServiceGrpc.FeatureServiceImplBase() {

    override fun getFeature(
        request: GetFeatureRequest,
        responseObserver: StreamObserver<GetFeatureResponse>,
    ) {
        try {
            val feature = featureService.getFeature(request.userId, request.featureId)
            val response = GetFeatureResponse.newBuilder()
                .setFeature(feature.toProto())
                .build()
            responseObserver.onNext(response)
            responseObserver.onCompleted()
        } catch (e: NotFoundException) {
            responseObserver.onError(
                Status.NOT_FOUND
                    .withDescription(e.message)
                    .asRuntimeException()
            )
        }
    }

    override fun listFeatures(
        request: ListFeaturesRequest,
        responseObserver: StreamObserver<ListFeaturesResponse>,
    ) {
        try {
            val features = featureService.listFeatures(
                request.userId,
                request.limit,
                request.offset
            )
            val response = ListFeaturesResponse.newBuilder()
                .addAllFeatures(features.map { it.toProto() })
                .setTotal(features.size)
                .build()
            responseObserver.onNext(response)
            responseObserver.onCompleted()
        } catch (e: Exception) {
            responseObserver.onError(
                Status.INTERNAL
                    .withDescription("Internal error")
                    .asRuntimeException()
            )
        }
    }
}
```

**gRPC Test Pattern**:

```kotlin
@ExtendWith(MockitoExtension::class)
class FeatureGrpcServiceTest {

    @Mock
    private lateinit var service: FeatureService

    @InjectMocks
    private lateinit var grpcService: FeatureGrpcService

    @Test
    fun `should return features via gRPC`() {
        // given
        val request = ListFeaturesRequest.newBuilder()
            .setUserId("user-id")
            .setLimit(20)
            .setOffset(0)
            .build()
        val responseObserver = mock<StreamObserver<ListFeaturesResponse>>()

        `when`(service.listFeatures("user-id", 20, 0))
            .thenReturn(listOf(/* features */))

        // when
        grpcService.listFeatures(request, responseObserver)

        // then
        verify(responseObserver).onNext(any())
        verify(responseObserver).onCompleted()
        verify(responseObserver, never()).onError(any())
    }
}
```

### DEVELOPMENT WORKFLOW LAYER ARCHITECTURE

The project follows a clean architecture with these layers:

```
┌─────────────────────────────────────┐
│   GraphQL Controller                │  ← Request entry (graphql/controller/)
│   @PreAuthorize, @UserId            │
├─────────────────────────────────────┤
│   GraphQL Service (gRPC Client)     │  ← Service aggregation (graphql/service/)
│   @GrpcClient("feature-grpc")       │
├─────────────────────────────────────┤
│   gRPC Server (@GrpcService)        │  ← {module}/controller/
│   StreamObserver<Response>          │
├─────────────────────────────────────┤
│   Business Logic Service            │  ← {module}/service/
│   @Transactional                    │
├─────────────────────────────────────┤
│   Repository (JPA + QueryDSL)       │  ← domain/repository/
│   Database Access                   │
└─────────────────────────────────────┘
```

### QUICK COMMANDS REFERENCE

```bash
./gradlew clean build -x test          # Full build
./gradlew :protobuf:clean :protobuf:build  # Proto rebuild
./gradlew :graphql:bootRun             # Run GraphQL gateway
./gradlew :user:compileKotlin          # Compile specific module
./gradlew :module:test                 # Run tests
./gradlew :module:dependencies         # View dependency tree
```

### KEY TECHNICAL STACK

- **Language**: Kotlin 1.8.22
- **Framework**: Spring Boot 3.1.4
- **Java**: JDK 17
- **API Gateway**: GraphQL (client-facing)
- **Service-to-service**: gRPC with Protocol Buffers 3
- **Testing**: JUnit5 + Mockito
- **Database**: MySQL 8.0.28 (with JPA) + Redis + DynamoDB
- **Build Tool**: Gradle with Kotlin DSL

This is a well-architected template project designed for AI-assisted development with comprehensive skills documentation for gRPC, GraphQL, entities, testing, and planning workflows.

